public class OddEvenJump {

    public int getNextIndexOdd(int start, int[] arr) {
        int nextMax = Integer.MAX_VALUE;
        int index = -1;
        for (int i = start + 1; i < arr.length; i++) {
            if (arr[i] >= arr[start] && arr[i] < nextMax) {
                nextMax = arr[i];
                index = i;
            }
        }
        return index;
    }

    public int getNextIndexEven(int start, int[] arr) {
        int nextMin = Integer.MIN_VALUE;
        int index = -1;
        for (int i = start + 1; i < arr.length; i++) {
            if (arr[i] <= arr[start] && arr[i] > nextMin) {
                nextMin = arr[i];
                index = i;
            }
        }
        return index;
    }

    public int getNextIndex(int start, int[] arr, boolean isOdd) {
        return isOdd ? getNextIndexOdd(start, arr) : getNextIndexEven(start, arr);
    }


    private boolean isPossibleToReachEnd(int index, int[] arr, boolean isOdd, Map<String, Boolean> map) {
        if (index == arr.length - 1) {
            return true;
        }

        if (map.containsKey(index + (isOdd ? "T" : "F")))
            return map.get(index + (isOdd ? "T" : "F"));

        int nextIndex = getNextIndex(index, arr, isOdd);
        if (nextIndex == -1) {
            map.put(index + (isOdd ? "T" : "F"), false);
            return false;
        }
        boolean result = isPossibleToReachEnd(nextIndex, arr, !isOdd, map);
        map.put(index + (isOdd ? "T" : "F"), result);
        return result;
    }

    public int oddEvenJumps(int[] arr) {
        long start = System.currentTimeMillis();
        Map<String, Boolean> map = new HashMap<>();
        int n = arr.length;
        int result = 0;
        for (int index = 0; index < n; index++){
            if (isPossibleToReachEnd(index, arr, true, map))
                result++;
        }
        long end = System.currentTimeMillis();
        double seconds = (end - start) / 1000.0;
        System.out.println("==============" + seconds + "=======");
        return result;
    }

    public static void main(String[] args) {
        OddEvenJump oddEvenJump = new OddEvenJump();
        System.out.println(oddEvenJump.oddEvenJumps(Nums.nums));
    }
}
